function DefEvidenceTimeUnits() {}
DefEvidenceTimeUnits.dataBinding = "/ds/EnterVariableData/TrialNotice/defEvidenceTimeUnits";
DefEvidenceTimeUnits.tabIndex = __tabIdx++;
DefEvidenceTimeUnits.helpText = "Select unit time";
DefEvidenceTimeUnits.mandatoryOn = [DefEvidenceTime.dataBinding];
DefEvidenceTimeUnits.isMandatory = function()
{	var val = Services.getValue(DefEvidenceTime.dataBinding);
	return( null != val && "" != val );
}	
DefEvidenceTimeUnits.isTemporary = function(){  return true; }	
DefEvidenceTimeUnits.enableOn = [DefEvidenceTime.dataBinding];
DefEvidenceTimeUnits.isEnabled = function(){ return DefEvidenceTime.isEnabled();}
DefEvidenceTimeUnits.logicOn = [DefEvidenceTime.dataBinding];
DefEvidenceTimeUnits.logic = function()
{	if( !DefEvidenceTime.isEnabled())
	Services.setValue(DefEvidenceTimeUnits.dataBinding,"");			
}
